import React, { useState } from 'react';
import { useDispatch } from 'react-redux';
import Button from '@material-ui/core/Button';
import { deleteCategory } from '../../../api';

function DeleteCategory({ category, handleCloseDialog }) { // Tar in kategorin som en parameter
  const [confirmDelete, setConfirmDelete] = useState(false);
  const dispatch = useDispatch();

  const handleDeleteCategory = () => {
    if (confirmDelete) {
      console.log("Deleting category: ", category);
      dispatch(deleteCategory(category));
      setConfirmDelete(false);
      handleCloseDialog();
    } else {
      setConfirmDelete(true);
    }
  };

  return (
    <div>
      <h3>Delete category</h3>
      <p>Are you sure you want to delete the category "{category}"?</p>
      {confirmDelete && (
        <Button variant="contained" color="secondary" onClick={handleDeleteCategory}>
          Yes, delete
        </Button>
      )}
      {!confirmDelete && (
        <Button variant="contained" color="primary" onClick={handleDeleteCategory}>
          Delete category
        </Button>
      )}
    </div>
  );
}

export default DeleteCategory;
